-- AUTO-GENERATED sync script for today_fridge.ingredient_master
-- Generated by export_ingredient_master_sync_sql.py
--
-- Apply with:
--   psql -d today_fridge -f sync_ingredient_master.sql
--
BEGIN;

-- This design allows multiple rows to share normalized_name.
ALTER TABLE today_fridge.ingredient_master
  DROP CONSTRAINT IF EXISTS ingredient_master_normalized_name_key;

CREATE TEMP TABLE tmp_ingredient_master_sync (LIKE today_fridge.ingredient_master INCLUDING ALL);


-- Upsert (ingredient_id is primary key)
SELECT ingredient_id, category_id, canonical_name, normalized_name, alias_text, standard_unit, description, is_active, embedding, embedding_updated_at, created_at, updated_at FROM tmp_ingredient_master_sync
ON CONFLICT (ingredient_id) DO UPDATE SET
  category_id = EXCLUDED.category_id,
  canonical_name = EXCLUDED.canonical_name,
  normalized_name = EXCLUDED.normalized_name,
  alias_text = EXCLUDED.alias_text,
  standard_unit = EXCLUDED.standard_unit,
  description = EXCLUDED.description,
  is_active = EXCLUDED.is_active,
  embedding = EXCLUDED.embedding,
  embedding_updated_at = EXCLUDED.embedding_updated_at,
  created_at = EXCLUDED.created_at,
  updated_at = EXCLUDED.updated_at;

-- Exact sync: delete rows not present in dump
-- FK 참조를 먼저 정리한 뒤 ingredient_master를 삭제한다.
CREATE TEMP TABLE tmp_obsolete_ingredient_ids AS
SELECT t.ingredient_id
FROM today_fridge.ingredient_master t
WHERE NOT EXISTS (
  SELECT 1 FROM tmp_ingredient_master_sync s WHERE s.ingredient_id = t.ingredient_id
);

-- child table cleanup (obsolete ingredient_id 참조 제거)
DELETE FROM today_fridge.recipe_ingredient
WHERE ingredient_master_id IN (SELECT ingredient_id FROM tmp_obsolete_ingredient_ids);

DELETE FROM today_fridge.user_ingredient
WHERE ingredient_master_id IN (SELECT ingredient_id FROM tmp_obsolete_ingredient_ids);

DELETE FROM today_fridge.shopping_item_mcp
WHERE ingredient_master_id IN (SELECT ingredient_id FROM tmp_obsolete_ingredient_ids);

DELETE FROM today_fridge.substitute_graph
WHERE base_ingredient_id IN (SELECT ingredient_id FROM tmp_obsolete_ingredient_ids)
   OR sub_ingredient_id IN (SELECT ingredient_id FROM tmp_obsolete_ingredient_ids);

DELETE FROM today_fridge.ingredient_master t
WHERE NOT EXISTS (
  SELECT 1 FROM tmp_ingredient_master_sync s WHERE s.ingredient_id = t.ingredient_id
);

-- Reset sequence to max(ingredient_id)
SELECT setval(
  'today_fridge.ingredient_master_ingredient_id_seq',
  COALESCE((SELECT MAX(ingredient_id) FROM today_fridge.ingredient_master), 1),
  true
);

COMMIT;
